import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(p1, p2):
        return np.linalg.norm(p1 - p2) / truck_speed

    def penalty_for_missing_window(arrival_time, window_start, window_end):
        if arrival_time > window_end:
            return 10000  # A high penalty for missing a window
        elif arrival_time < window_start:
            return (window_start - arrival_time) * 0.5  # Waiting cost
        return 0

    def predictive_congestion_adjustment(destination, all_positions, future_time):
        future_distances = np.array([np.linalg.norm(destination - pos) for pos in all_positions])
        adjusted_traffic_factor = np.sum(np.exp(-future_distances / 10))  # Adjusted decay to model future congestion better
        return adjusted_traffic_factor * 0.05  # Updated scale factor for predictive congestion

    min_cost = float('inf')
    best_node = 'None'

    for idx, customer in enumerate(unvisited_customers):
        t_time = travel_time(cur_truck_pos, customer)
        arrival_time = current_time + t_time
        window_start, window_end = time_windows[idx]

        wait_penalty = penalty_for_missing_window(arrival_time, window_start, window_end)
        if arrival_time > window_end:
            continue  # Skip as this option is infeasible due to missed window

        congestion_penalty = predictive_congestion_adjustment(customer, all_truck_pos, arrival_time)
        total_cost = t_time + wait_penalty + congestion_penalty

        if total_cost < min_cost:
            min_cost = total_cost
            best_node = idx

    return best_node

